	"github.com/pkg/errors"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/mock"
)

// MockConsulClient is a mock implementation of consul.Client interface
type MockConsulClient struct {
	mock.Mock
}

func (m *MockConsulClient) GetKey(key string) (*api.KVPair, error) {
	args := m.Called(key)
	if args.Get(0) == nil {
		return nil, args.Error(1)
	}
	return args.Get(0).(*api.KVPair), args.Error(1)
}

func (m *MockConsulClient) PutKey(key string, value interface{}) error {
	args := m.Called(key, value)
	return args.Error(0)
}

func TestNewStorage(t *testing.T) {
	mockConsul := &MockConsulClient{}
	s := newStorage(mockConsul)

	assert.NotNil(t, s)
	assert.Equal(t, mockConsul, s.consulClient)
}

func TestGetExecutedMigrations(t *testing.T) {
	testCases := []struct {
		name           string
		consulSetup    func(*MockConsulClient)
		expectedResult map[string]migrationInfo
		expectError    bool
		errorContains  string
	}{
		{
			name: "Consul error",
			consulSetup: func(mc *MockConsulClient) {
				mc.On("GetKey", MigrationHistoryKey).Return(nil, errors.New("consul error"))
			},
			expectedResult: nil,
			expectError:    true,
			errorContains:  "consul error",
		},
		{
			name: "Empty key",
			consulSetup: func(mc *MockConsulClient) {
				mc.On("GetKey", MigrationHistoryKey).Return(nil, nil)
			},
			expectedResult: map[string]migrationInfo{},
			expectError:    false,
		},
		{
			name: "Empty value",
			consulSetup: func(mc *MockConsulClient) {
				kvPair := &api.KVPair{
					Key:   MigrationHistoryKey,
					Value: []byte{},
				}
				mc.On("GetKey", MigrationHistoryKey).Return(kvPair, nil)
			},
			expectedResult: map[string]migrationInfo{},
			expectError:    false,
		},
		{
			name: "Invalid JSON",
			consulSetup: func(mc *MockConsulClient) {
				kvPair := &api.KVPair{
					Key:   MigrationHistoryKey,
					Value: []byte("invalid json"),
				}
				mc.On("GetKey", MigrationHistoryKey).Return(kvPair, nil)
			},
			expectedResult: nil,
			expectError:    true,
			errorContains:  "invalid",
		},
		{
			name: "Nil migrations",
			consulSetup: func(mc *MockConsulClient) {
				history := migrationHistory{
					Migrations: nil,
				}
				historyBytes, _ := json.Marshal(history)
				kvPair := &api.KVPair{
					Key:   MigrationHistoryKey,
					Value: historyBytes,
				}
				mc.On("GetKey", MigrationHistoryKey).Return(kvPair, nil)
			},
			expectedResult: map[string]migrationInfo{},
			expectError:    false,
		},
		{
			name: "Successful retrieval",
			consulSetup: func(mc *MockConsulClient) {
				migrations := map[string]migrationInfo{
					"migration1": {
						Name:        "First Migration",
						Version:     1,
						ID:          "migration1",
						Description: "First migration description",
						ExecutedAt:  time.Date(2023, 1, 1, 12, 0, 0, 0, time.UTC),
						DurationMs:  500,
					},
					"migration2": {
						Name:        "Second Migration",
						Version:     2,
						ID:          "migration2",
						Description: "Second migration description",
						ExecutedAt:  time.Date(2023, 1, 2, 12, 0, 0, 0, time.UTC),
						DurationMs:  750,
					},
				}

				history := migrationHistory{
					Migrations: migrations,
				}
				historyBytes, _ := json.Marshal(history)
				kvPair := &api.KVPair{
					Key:   MigrationHistoryKey,
					Value: historyBytes,
				}
				mc.On("GetKey", MigrationHistoryKey).Return(kvPair, nil)
			},
			expectedResult: map[string]migrationInfo{
				"migration1": {
					Name:        "First Migration",
					Version:     1,
					ID:          "migration1",
					Description: "First migration description",
					ExecutedAt:  time.Date(2023, 1, 1, 12, 0, 0, 0, time.UTC),
					DurationMs:  500,
				},
				"migration2": {
					Name:        "Second Migration",
					Version:     2,
					ID:          "migration2",
					Description: "Second migration description",
					ExecutedAt:  time.Date(2023, 1, 2, 12, 0, 0, 0, time.UTC),
					DurationMs:  750,
				},
			},
			expectError: false,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			// Setup
			mockConsul := &MockConsulClient{}
			tc.consulSetup(mockConsul)

			s := newStorage(mockConsul)
			ctx := log.NewContext(nil)

			// Execute
			result, err := s.GetExecutedMigrations(ctx)

			// Verify
			if tc.expectError {
				assert.Error(t, err)
				if tc.errorContains != "" {
					assert.Contains(t, err.Error(), tc.errorContains)
				}
			} else {
				assert.NoError(t, err)
			}

			assert.Equal(t, tc.expectedResult, result)
			mockConsul.AssertExpectations(t)
		})
	}
}

func TestSaveMigrationHistory(t *testing.T) {
