func TestStructFieldTags(t *testing.T) {
	testCases := []struct {
		name          string
		structType    interface{}
		fieldTagTests map[string]string // field name -> expected json tag
	}{
		{
			name:       "migrationInfo struct",
			structType: migrationInfo{},
			fieldTagTests: map[string]string{
				"Name":        "name",
				"Version":     "version",
				"ID":          "id",
				"Description": "description",
				"ExecutedAt":  "executed_at",
				"DurationMs":  "duration_ms",
			},
		},
		{
			name:       "migrationHistory struct",
			structType: migrationHistory{},
			fieldTagTests: map[string]string{
				"Migrations": "migrations",
			},
		},
